858b170c-6108-47d0-a9af-68fc240f1593	b2fc233b-0ef7-48b7-82d9-d4b5c28c66c5	Cash Flow Fund X	fund	draft	506_b	2027-12-01	Cash Flow Fund X LLC	f	t	Sunbelt Area Geographically	US	\N	\N		TX	\N	deal-assets/cash-flow-fund-x-858b170c-6108-47d0-a9af-68fc240f1593/massive-access-pic_63bdfbf5-8bc5-4018-90a4-fa788cf41cf2_1779678035602.jpeg;deal-assets/cash-flow-fund-x-858b170c-6108-47d0-a9af-68fc240f1593/massive-access-pic_2298fceb-1f40-4287-8d7d-330719f2055b_1779678038610.jpeg;deal-assets/cash-flow-fund-x-858b170c-6108-47d0-a9af-68fc240f1593/massive-access-events-image_d4928180-e0f7-4dfe-9e3b-8c4d718a51f7_1779679511720.jpeg;deal-assets/cash-flow-fund-x-858b170c-6108-47d0-a9af-68fc240f1593/massive-access-pic_d19ba301-badd-430b-8972-61ce97100518_1779679743586.jpeg	<p><img src="data:image/jpeg;base64," /></p><p><strong>INVESTMENT THESIS</strong></p><p><span style="color:rgb(16, 46, 80)">1. Cashflow Fund X, an open-ended fund focused on providing </span><strong style="color:rgb(16, 46, 80)">equity to commercial real estate properties</strong><span style="color:rgb(16, 46, 80)">.</span></p><p></p><p><span style="color:rgb(16, 46, 80)">2. A dislocation in the capital markets has created a unique opportunity to provide capital </span><strong style="color:rgb(16, 46, 80)">through preferred equity and mezzanine debt</strong></p><p></p><p><span style="color:rgb(16, 46, 80)">3. This fund will be focused on providing </span><strong style="color:rgb(16, 46, 80)">current cash yield </strong><span style="color:rgb(16, 46, 80)">while investing in preferred positions in the underlying investment</span></p><p></p><p><span style="color:rgb(16, 46, 80)">4. CashFlow fund strategy is founded on the belief that </span><strong style="color:rgb(16, 46, 80)">downside risk can be limited, and thus losses avoided</strong><span style="color:rgb(16, 46, 80)">, through two complementary approaches: rigorous credit analysis and active portfolio management</span></p><p></p><p><strong>Investment Objective</strong></p><p></p><p>Cashflow Fund X will invest in:</p><p>•Cash Flowing Commercial Properties</p><p>•Class A Retail Centers</p><p>•MHPs &amp; RV Parks</p><p>•Cashflowing Businesses</p><p>•Storage Facilities</p><p>•Residential Assisted Living</p><p>•Short Term High Yield Loans</p><p>•Liquid Assets While on Hold for Deals</p><p></p><p>Across sunbelt with heavy focus on Texas</p>	\N	[{"id":"preset-0","metric":"Annualized return","newClass":"10%","isPreset":true},{"id":"preset-1","metric":"Average cash-on-cash","newClass":"10%","isPreset":true},{"id":"preset-2","metric":"Equity multiple","newClass":"1.50","isPreset":true},{"id":"preset-3","metric":"IRR","newClass":"10%","isPreset":true},{"id":"preset-4","metric":"Holding period","newClass":"Minimum 1+ Years","isPreset":true}]	\N	\N	draft_hidden	show_on_dashboard	f		[]	["deal-assets/cash-flow-fund-x-858b170c-6108-47d0-a9af-68fc240f1593/massive-access-events-image_d4928180-e0f7-4dfe-9e3b-8c4d718a51f7_1779679511720.jpeg","deal-assets/cash-flow-fund-x-858b170c-6108-47d0-a9af-68fc240f1593/massive-access-pic_d19ba301-badd-430b-8972-61ce97100518_1779679743586.jpeg"]	2026-05-25 08:28:36.019574+05:30	2xi_J7EFsUUfbHVw.ogwsRT6_P3ChLUHP9hEbEw.9Kl_4NoTXT9_-9x3oMR7AIGO9R1bqZLbtBwfdTMRkDbiXEOf	{"v":1,"visibility":{"make_announcement":true,"overview":true,"offering_information":true,"gallery":true,"summary":true,"documents":true,"assets":true,"key_highlights":true,"funding_instructions":true},"sections":[]}	\N	\N
